static char *choose_pix_fmts(OutputStream *ost)

{

     if (ost->keep_pix_fmt) {

        if (ost->filter)

            avfilter_graph_set_auto_convert(ost->filter->graph->graph,

                                            AVFILTER_AUTO_CONVERT_NONE);

        if (ost->st->codec->pix_fmt == PIX_FMT_NONE)

            return NULL;

        return av_strdup(av_get_pix_fmt_name(ost->st->codec->pix_fmt));

    }

    if (ost->st->codec->pix_fmt != PIX_FMT_NONE) {

        return av_strdup(av_get_pix_fmt_name(choose_pixel_fmt(ost->st, ost->enc, ost->st->codec->pix_fmt)));

    } else if (ost->enc->pix_fmts) {

        const enum PixelFormat *p;

        AVIOContext *s = NULL;

        uint8_t *ret;

        int len;



        if (avio_open_dyn_buf(&s) < 0)

            exit_program(1);



        p = ost->enc->pix_fmts;

        if (ost->st->codec->strict_std_compliance <= FF_COMPLIANCE_UNOFFICIAL) {

            if (ost->st->codec->codec_id == CODEC_ID_MJPEG) {

                p = (const enum PixelFormat[]) { PIX_FMT_YUVJ420P, PIX_FMT_YUVJ422P, PIX_FMT_YUV420P, PIX_FMT_YUV422P, PIX_FMT_NONE };

            } else if (ost->st->codec->codec_id == CODEC_ID_LJPEG) {

                p = (const enum PixelFormat[]) { PIX_FMT_YUVJ420P, PIX_FMT_YUVJ422P, PIX_FMT_YUVJ444P, PIX_FMT_YUV420P,

                                                    PIX_FMT_YUV422P, PIX_FMT_YUV444P, PIX_FMT_BGRA, PIX_FMT_NONE };

            }

        }



        for (; *p != PIX_FMT_NONE; p++) {

            const char *name = av_get_pix_fmt_name(*p);

            avio_printf(s, "%s:", name);

        }

        len = avio_close_dyn_buf(s, &ret);

        ret[len - 1] = 0;

        return ret;

    } else

        return NULL;

}

static void imdct12(INTFLOAT *out, INTFLOAT *in)

{

    INTFLOAT in0, in1, in2, in3, in4, in5, t1, t2;



    in0  = in[0*3];

    in1  = in[1*3] + in[0*3];

    in2  = in[2*3] + in[1*3];

    in3  = in[3*3] + in[2*3];

    in4  = in[4*3] + in[3*3];

    in5  = in[5*3] + in[4*3];

    in5 += in3;

    in3 += in1;



    in2  = MULH3(in2, C3, 2);

    in3  = MULH3(in3, C3, 4);



    t1   = in0 - in4;

    t2   = MULH3(in1 - in5, C4, 2);



    out[ 7] =

    out[10] = t1 + t2;

    out[ 1] =

    out[ 4] = t1 - t2;



    in0    += SHR(in4, 1);

    in4     = in0 + in2;

    in5    += 2*in1;

    in1     = MULH3(in5 + in3, C5, 1);

    out[ 8] =

    out[ 9] = in4 + in1;

    out[ 2] =

    out[ 3] = in4 - in1;



    in0    -= in2;

    in5     = MULH3(in5 - in3, C6, 2);

    out[ 0] =

    out[ 5] = in0 - in5;

    out[ 6] =

    out[11] = in0 + in5;

}

static inline int ultrasparc_tag_match(SparcTLBEntry *tlb,

                                       uint64_t address, uint64_t context,

                                       target_phys_addr_t *physical,

                                       int is_nucleus)

{

    uint64_t mask;



    switch ((tlb->tte >> 61) & 3) {

    default:

    case 0x0: // 8k

        mask = 0xffffffffffffe000ULL;

        break;

    case 0x1: // 64k

        mask = 0xffffffffffff0000ULL;

        break;

    case 0x2: // 512k

        mask = 0xfffffffffff80000ULL;

        break;

    case 0x3: // 4M

        mask = 0xffffffffffc00000ULL;

        break;

    }



    // valid, context match, virtual address match?

    if (TTE_IS_VALID(tlb->tte) &&

        ((is_nucleus && compare_masked(0, tlb->tag, 0x1fff))

         || TTE_IS_GLOBAL(tlb->tte) || compare_masked(context, tlb->tag, 0x1fff))

        && compare_masked(address, tlb->tag, mask))

    {

        // decode physical address

        *physical = ((tlb->tte & mask) | (address & ~mask)) & 0x1ffffffe000ULL;

        return 1;

    }



    return 0;

}

static int vmdvideo_decode_init(AVCodecContext *avctx)

{

    VmdVideoContext *s = avctx->priv_data;

    int i;

    unsigned int *palette32;

    int palette_index = 0;

    unsigned char r, g, b;

    unsigned char *vmd_header;

    unsigned char *raw_palette;



    s->avctx = avctx;

    avctx->pix_fmt = PIX_FMT_PAL8;

    dsputil_init(&s->dsp, avctx);



    /* make sure the VMD header made it */

    if (s->avctx->extradata_size != VMD_HEADER_SIZE) {

        av_log(s->avctx, AV_LOG_ERROR, "VMD video: expected extradata size of %d\n",

            VMD_HEADER_SIZE);

        return -1;

    }

    vmd_header = (unsigned char *)avctx->extradata;



    s->unpack_buffer_size = AV_RL32(&vmd_header[800]);

    s->unpack_buffer = av_malloc(s->unpack_buffer_size);

    if (!s->unpack_buffer)

        return -1;



    /* load up the initial palette */

    raw_palette = &vmd_header[28];

    palette32 = (unsigned int *)s->palette;

    for (i = 0; i < PALETTE_COUNT; i++) {

        r = raw_palette[palette_index++] * 4;

        g = raw_palette[palette_index++] * 4;

        b = raw_palette[palette_index++] * 4;

        palette32[i] = (r << 16) | (g << 8) | (b);

    }



    s->frame.data[0] = s->prev_frame.data[0] = NULL;



    return 0;

}

static inline void host_to_target_siginfo_noswap(target_siginfo_t *tinfo,

                                                 const siginfo_t *info)

{

    int sig = host_to_target_signal(info->si_signo);

    tinfo->si_signo = sig;

    tinfo->si_errno = 0;

    tinfo->si_code = info->si_code;



    if (sig == TARGET_SIGILL || sig == TARGET_SIGFPE || sig == TARGET_SIGSEGV

            || sig == TARGET_SIGBUS || sig == TARGET_SIGTRAP) {

        /* Should never come here, but who knows. The information for

           the target is irrelevant.  */

        tinfo->_sifields._sigfault._addr = 0;

    } else if (sig == TARGET_SIGIO) {

        tinfo->_sifields._sigpoll._band = info->si_band;

        tinfo->_sifields._sigpoll._fd = info->si_fd;

    } else if (sig == TARGET_SIGCHLD) {

        tinfo->_sifields._sigchld._pid = info->si_pid;

        tinfo->_sifields._sigchld._uid = info->si_uid;

        tinfo->_sifields._sigchld._status

                = host_to_target_waitstatus(info->si_status);

        tinfo->_sifields._sigchld._utime = info->si_utime;

        tinfo->_sifields._sigchld._stime = info->si_stime;

    } else if (sig >= TARGET_SIGRTMIN) {

        tinfo->_sifields._rt._pid = info->si_pid;

        tinfo->_sifields._rt._uid = info->si_uid;

        /* XXX: potential problem if 64 bit */

        tinfo->_sifields._rt._sigval.sival_ptr

                = (abi_ulong)(unsigned long)info->si_value.sival_ptr;

    }

}

static int qemu_savevm_state(Monitor *mon, QEMUFile *f)

{

    int ret;



    if (qemu_savevm_state_blocked(mon)) {

        ret = -EINVAL;

        goto out;

    }



    ret = qemu_savevm_state_begin(f, 0, 0);

    if (ret < 0)

        goto out;



    do {

        ret = qemu_savevm_state_iterate(f);

        if (ret < 0)

            goto out;

    } while (ret == 0);



    ret = qemu_savevm_state_complete(f);



out:

    if (ret == 0) {

        ret = qemu_file_get_error(f);

    }



    return ret;

}

static int parse_nal_units(AVCodecParserContext *s, const uint8_t *buf,

                           int buf_size, AVCodecContext *avctx)

{

    HEVCParserContext *ctx = s->priv_data;

    int ret, i;



    ret = ff_h2645_packet_split(&ctx->pkt, buf, buf_size, avctx, 0, 0,

                                AV_CODEC_ID_HEVC);

    if (ret < 0)

        return ret;



    for (i = 0; i < ctx->pkt.nb_nals; i++) {

        H2645NAL *nal = &ctx->pkt.nals[i];



        /* ignore everything except parameter sets and VCL NALUs */

        switch (nal->type) {

        case NAL_VPS: ff_hevc_decode_nal_vps(&nal->gb, avctx, &ctx->ps);    break;

        case NAL_SPS: ff_hevc_decode_nal_sps(&nal->gb, avctx, &ctx->ps, 1); break;

        case NAL_PPS: ff_hevc_decode_nal_pps(&nal->gb, avctx, &ctx->ps);    break;

        case NAL_TRAIL_R:

        case NAL_TRAIL_N:

        case NAL_TSA_N:

        case NAL_TSA_R:

        case NAL_STSA_N:

        case NAL_STSA_R:

        case NAL_BLA_W_LP:

        case NAL_BLA_W_RADL:

        case NAL_BLA_N_LP:

        case NAL_IDR_W_RADL:

        case NAL_IDR_N_LP:

        case NAL_CRA_NUT:

        case NAL_RADL_N:

        case NAL_RADL_R:

        case NAL_RASL_N:

        case NAL_RASL_R:

            if (buf == avctx->extradata) {

                av_log(avctx, AV_LOG_ERROR, "Invalid NAL unit: %d\n", nal->type);

                return AVERROR_INVALIDDATA;

            }

            hevc_parse_slice_header(s, nal, avctx);

            break;

        }

    }



    return 0;

}

