static inline int usb_bt_fifo_dequeue(struct usb_hci_in_fifo_s *fifo,

                USBPacket *p)

{

    int len;



    if (likely(!fifo->len))

        return USB_RET_STALL;



    len = MIN(p->len, fifo->fifo[fifo->start].len);

    memcpy(p->data, fifo->fifo[fifo->start].data, len);

    if (len == p->len) {

        fifo->fifo[fifo->start].len -= len;

        fifo->fifo[fifo->start].data += len;

    } else {

        fifo->start ++;

        fifo->start &= CFIFO_LEN_MASK;

        fifo->len --;

    }



    fifo->dstart += len;

    fifo->dlen -= len;

    if (fifo->dstart >= fifo->dsize) {

        fifo->dstart = 0;

        fifo->dsize = DFIFO_LEN_MASK + 1;

    }



    return len;

}

static void decode_src_opc(CPUTriCoreState *env, DisasContext *ctx, int op1)

{

    int r1;

    int32_t const4;

    TCGv temp, temp2;



    r1 = MASK_OP_SRC_S1D(ctx->opcode);

    const4 = MASK_OP_SRC_CONST4_SEXT(ctx->opcode);



    switch (op1) {

    case OPC1_16_SRC_ADD:

        gen_addi_d(cpu_gpr_d[r1], cpu_gpr_d[r1], const4);

        break;

    case OPC1_16_SRC_ADD_A15:

        gen_addi_d(cpu_gpr_d[r1], cpu_gpr_d[15], const4);

        break;

    case OPC1_16_SRC_ADD_15A:

        gen_addi_d(cpu_gpr_d[15], cpu_gpr_d[r1], const4);

        break;

    case OPC1_16_SRC_ADD_A:

        tcg_gen_addi_tl(cpu_gpr_a[r1], cpu_gpr_a[r1], const4);

        break;

    case OPC1_16_SRC_CADD:

        gen_condi_add(TCG_COND_NE, cpu_gpr_d[r1], const4, cpu_gpr_d[r1],

                      cpu_gpr_d[15]);

        break;

    case OPC1_16_SRC_CADDN:

        gen_condi_add(TCG_COND_EQ, cpu_gpr_d[r1], const4, cpu_gpr_d[r1],

                      cpu_gpr_d[15]);

        break;

    case OPC1_16_SRC_CMOV:

        temp = tcg_const_tl(0);

        temp2 = tcg_const_tl(const4);

        tcg_gen_movcond_tl(TCG_COND_NE, cpu_gpr_d[r1], cpu_gpr_d[15], temp,

                           temp2, cpu_gpr_d[r1]);

        tcg_temp_free(temp);

        tcg_temp_free(temp2);

        break;

    case OPC1_16_SRC_CMOVN:

        temp = tcg_const_tl(0);

        temp2 = tcg_const_tl(const4);

        tcg_gen_movcond_tl(TCG_COND_EQ, cpu_gpr_d[r1], cpu_gpr_d[15], temp,

                           temp2, cpu_gpr_d[r1]);

        tcg_temp_free(temp);

        tcg_temp_free(temp2);

        break;

    case OPC1_16_SRC_EQ:

        tcg_gen_setcondi_tl(TCG_COND_EQ, cpu_gpr_d[15], cpu_gpr_d[r1],

                            const4);

        break;

    case OPC1_16_SRC_LT:

        tcg_gen_setcondi_tl(TCG_COND_LT, cpu_gpr_d[15], cpu_gpr_d[r1],

                            const4);

        break;

    case OPC1_16_SRC_MOV:

        tcg_gen_movi_tl(cpu_gpr_d[r1], const4);

        break;

    case OPC1_16_SRC_MOV_A:

        const4 = MASK_OP_SRC_CONST4(ctx->opcode);

        tcg_gen_movi_tl(cpu_gpr_a[r1], const4);

        break;

    case OPC1_16_SRC_MOV_E:

        if (tricore_feature(env, TRICORE_FEATURE_16)) {

            tcg_gen_movi_tl(cpu_gpr_d[r1], const4);

            tcg_gen_sari_tl(cpu_gpr_d[r1+1], cpu_gpr_d[r1], 31);

        } /* TODO: else raise illegal opcode trap */

        break;

    case OPC1_16_SRC_SH:

        gen_shi(cpu_gpr_d[r1], cpu_gpr_d[r1], const4);

        break;

    case OPC1_16_SRC_SHA:

        gen_shaci(cpu_gpr_d[r1], cpu_gpr_d[r1], const4);

        break;

    }

}

static void dec_fpu(DisasContext *dc)

{

    if ((dc->tb_flags & MSR_EE_FLAG)

          && !(dc->env->pvr.regs[2] & PVR2_ILL_OPCODE_EXC_MASK)

          && !((dc->env->pvr.regs[2] & PVR2_USE_FPU_MASK))) {

        tcg_gen_movi_tl(cpu_SR[SR_ESR], ESR_EC_ILLEGAL_OP);

        t_gen_raise_exception(dc, EXCP_HW_EXCP);

        return;

    }



    qemu_log ("unimplemented FPU insn pc=%x opc=%x\n", dc->pc, dc->opcode);

    dc->abort_at_next_insn = 1;

}

static av_cold int mss2_decode_init(AVCodecContext *avctx)

{

    MSS2Context * const ctx = avctx->priv_data;

    MSS12Context *c = &ctx->c;

    int ret;

    c->avctx = avctx;

    avctx->coded_frame = &ctx->pic;

    if (ret = ff_mss12_decode_init(c, 1, &ctx->sc[0], &ctx->sc[1]))

        return ret;

    c->pal_stride   = c->mask_stride;

    c->pal_pic      = av_malloc(c->pal_stride * avctx->height);

    c->last_pal_pic = av_malloc(c->pal_stride * avctx->height);

    if (!c->pal_pic || !c->last_pal_pic) {

        mss2_decode_end(avctx);

        return AVERROR(ENOMEM);

    }

    if (ret = wmv9_init(avctx)) {

        mss2_decode_end(avctx);

        return ret;

    }

    ff_mss2dsp_init(&ctx->dsp);



    avctx->pix_fmt = c->free_colours == 127 ? AV_PIX_FMT_RGB555

                                            : AV_PIX_FMT_RGB24;



    return 0;

}

static void spapr_add_lmbs(DeviceState *dev, uint64_t addr_start, uint64_t size,

                           uint32_t node, bool dedicated_hp_event_source,

                           Error **errp)

{

    sPAPRDRConnector *drc;

    uint32_t nr_lmbs = size/SPAPR_MEMORY_BLOCK_SIZE;

    int i, fdt_offset, fdt_size;

    void *fdt;

    uint64_t addr = addr_start;



    for (i = 0; i < nr_lmbs; i++) {

        drc = spapr_drc_by_id(TYPE_SPAPR_DRC_LMB,

                              addr / SPAPR_MEMORY_BLOCK_SIZE);

        g_assert(drc);



        fdt = create_device_tree(&fdt_size);

        fdt_offset = spapr_populate_memory_node(fdt, node, addr,

                                                SPAPR_MEMORY_BLOCK_SIZE);



        spapr_drc_attach(drc, dev, fdt, fdt_offset, !dev->hotplugged, errp);

        addr += SPAPR_MEMORY_BLOCK_SIZE;

        if (!dev->hotplugged) {

            sPAPRDRConnectorClass *drck = SPAPR_DR_CONNECTOR_GET_CLASS(drc);

            /* guests expect coldplugged LMBs to be pre-allocated */

            drck->set_allocation_state(drc, SPAPR_DR_ALLOCATION_STATE_USABLE);

            drck->set_isolation_state(drc, SPAPR_DR_ISOLATION_STATE_UNISOLATED);

        }

    }

    /* send hotplug notification to the

     * guest only in case of hotplugged memory

     */

    if (dev->hotplugged) {

        if (dedicated_hp_event_source) {

            drc = spapr_drc_by_id(TYPE_SPAPR_DRC_LMB,

                                  addr_start / SPAPR_MEMORY_BLOCK_SIZE);

            spapr_hotplug_req_add_by_count_indexed(SPAPR_DR_CONNECTOR_TYPE_LMB,

                                                   nr_lmbs,

                                                   spapr_drc_index(drc));

        } else {

            spapr_hotplug_req_add_by_count(SPAPR_DR_CONNECTOR_TYPE_LMB,

                                           nr_lmbs);

        }

    }

}

e1000e_io_write(void *opaque, hwaddr addr,

                uint64_t val, unsigned size)

{

    E1000EState *s = opaque;

    uint32_t idx;



    switch (addr) {

    case E1000_IOADDR:

        trace_e1000e_io_write_addr(val);

        s->ioaddr = (uint32_t) val;

        return;

    case E1000_IODATA:

        if (e1000e_io_get_reg_index(s, &idx)) {

            trace_e1000e_io_write_data(idx, val);

            e1000e_core_write(&s->core, idx, val, sizeof(val));

        }

        return;

    default:

        trace_e1000e_wrn_io_write_unknown(addr);

        return;

    }

}

e1000e_write_ps_rx_descr(E1000ECore *core, uint8_t *desc,

                         struct NetRxPkt *pkt,

                         const E1000E_RSSInfo *rss_info,

                         size_t ps_hdr_len,

                         uint16_t(*written)[MAX_PS_BUFFERS])

{

    int i;

    union e1000_rx_desc_packet_split *d =

        (union e1000_rx_desc_packet_split *) desc;



    memset(d, 0, sizeof(*d));



    d->wb.middle.length0 = cpu_to_le16((*written)[0]);



    for (i = 0; i < PS_PAGE_BUFFERS; i++) {

        d->wb.upper.length[i] = cpu_to_le16((*written)[i + 1]);

    }



    e1000e_build_rx_metadata(core, pkt, pkt != NULL,

                             rss_info,

                             &d->wb.lower.hi_dword.rss,

                             &d->wb.lower.mrq,

                             &d->wb.middle.status_error,

                             &d->wb.lower.hi_dword.csum_ip.ip_id,

                             &d->wb.middle.vlan);



    d->wb.upper.header_status =

        cpu_to_le16(ps_hdr_len | (ps_hdr_len ? E1000_RXDPS_HDRSTAT_HDRSP : 0));



    trace_e1000e_rx_desc_ps_write((*written)[0], (*written)[1],

                                  (*written)[2], (*written)[3]);

}
